import 'package:flutter/material.dart';import 'package:provider/provider.dart';import '../providers/auth_provider.dart';import '../services/api_service.dart';import '../widgets/app_sidebar.dart';
class AppVersionsScreen extends StatefulWidget{const AppVersionsScreen({super.key});@override State<AppVersionsScreen> createState()=>_State();}
class _State extends State<AppVersionsScreen>{final api=ApiService();bool loading=true;String latest='';List<Map<String,dynamic>> users=[];@override void initState(){super.initState();load();}List<int> parts(String v)=>v.split('.').map((x)=>int.tryParse(x)??0).toList();bool current(String? v){if(v==null)return false;final a=parts(v),b=parts(latest);for(var i=0;i<3;i++){final x=i<a.length?a[i]:0,y=i<b.length?b[i]:0;if(x!=y)return x>y;}return true;}Future<void> load()async{final d=await api.getAppVersions();latest=d['latest_version']?.toString()??'';users=List<Map<String,dynamic>>.from(d['users']??const[]);if(mounted)setState(()=>loading=false);}@override Widget build(BuildContext context){final role=context.watch<AuthProvider>().role??'trainer';return Scaffold(drawer:AppSidebar(role:role),appBar:AppBar(title:const Text('Android App Versions'),actions:[IconButton(onPressed:load,icon:const Icon(Icons.refresh))]),body:loading?const Center(child:CircularProgressIndicator()):ListView(padding:const EdgeInsets.all(20),children:[Card(child:ListTile(leading:const Icon(Icons.system_update),title:Text('Current release: v$latest'),subtitle:const Text('Participants on older versions should update.'))),...users.map((u){final v=u['app_version']?.toString();return Card(child:ListTile(title:Text(u['full_name']?.toString()??''),subtitle:Text('${u['username']} • Last ping ${u['last_app_ping']??'Never'}'),trailing:Chip(label:Text(v==null?'Not installed':current(v)?'v$v • Current':'v$v • Update'),backgroundColor:v!=null&&current(v)?Colors.green.shade100:v==null?Colors.grey.shade200:Colors.red.shade100)));})]));}}
